// Données par défaut converties en objets {codart, libelle, qte, nb}. Remplacées
// par consoImported si l'utilisateur importe un export plus récent (consoImportFile).
const CONSO_DEFAULT = CONSO_DEFAULT_RAW.map(([codart, libelle, qte, nb]) => ({codart, libelle, qte, nb}));

let consoImported = null;           // null = utilise CONSO_DEFAULT
let consoImportedPeriodDays = null; // idem, en jours

function consoGetActive() {
  return {
    items: consoImported || CONSO_DEFAULT,
    periodDays: consoImportedPeriodDays || CONSO_PERIOD_DAYS_DEFAULT,
  };
}

function consoGetEntry(codart_wip) {
  if (!codart_wip) return null;
  const { items } = consoGetActive();
  return items.find(x => x.codart === codart_wip) || null;
}

// Moyenne mensuelle = consommation totale ÷ nombre de mois couverts par TOUTE la
// période de l'export (pas une fenêtre glissante — choix explicite de Stéphane).
function consoGetMoyenneMensuelle(codart_wip) {
  const entry = consoGetEntry(codart_wip);
  if (!entry) return null;
  const { periodDays } = consoGetActive();
  const moisPeriode = periodDays / 30.4375;
  return moisPeriode > 0 ? entry.qte / moisPeriode : null;
}

// Couverture en mois = stock actuel disponible ÷ consommation moyenne mensuelle.
// Retourne null si aucune consommation historique connue pour cette référence
// (référence neuve, ou non couverte par l'export) — on ne peut alors rien affirmer,
// mieux vaut afficher "—" qu'un chiffre inventé.
function consoGetCouvertureMois(codart_wip) {
  const moyenne = consoGetMoyenneMensuelle(codart_wip);
  if (!moyenne || moyenne <= 0) return null;
  const stock = (typeof pdpGetStockForWip === 'function') ? pdpGetStockForWip(codart_wip) : 0;
  return stock / moyenne;
}

function consoFmtMois(mois) {
  if (mois === null || mois === undefined) return '—';
  if (mois >= 10) return Math.round(mois) + ' mois';
  return mois.toFixed(1) + ' mois';
}

// Style cohérent (couleur/fond) réutilisé partout où la couverture est affichée :
// tuiles PDP, onglet dédié, onglet Besoins. Seuils : <1 mois = critique, <3 mois =
// à surveiller, sinon couvert. Pas de consommation connue = neutre (gris).
function consoCouvertureStyle(mois) {
  if (mois === null || mois === undefined) return {bg:'var(--bg)', text:'var(--text-faint)', dot:'var(--text-faint)'};
  if (mois < 1)  return {bg:'#FCEBEB', text:'#A32D2D', dot:'#A32D2D'};
  if (mois < 3)  return {bg:'#FEF5E7', text:'#633806', dot:'#D4880A'};
  return {bg:'#EAF3DE', text:'#27500A', dot:'#1D9E75'};
}

// ── Import d'un export de consommation plus récent (remplace CONSO_DEFAULT) ────
function consoImportFile(input) {
  const file = input.files && input.files[0];
  if (!file) return;
  if (typeof showToast === 'function') showToast('Chargement ' + file.name + '…');

  const reader = new FileReader();
  reader.onload = (e) => {
    const doImport = () => {
      try {
        const wb = XLSX.read(e.target.result, {type:'array', cellDates:true});
        const ws = wb.Sheets[wb.SheetNames[0]];
        const json = XLSX.utils.sheet_to_json(ws, {defval:''});

        const agg = {};
        let dmin = null, dmax = null;
        json.forEach(r => {
          const codart = String(r.CODART||'').trim();
          if (!codart) return;
          const qte = Number(r.QTEMVT)||0;
          const libelle = String(r.LIBART||'').trim();
          if (!agg[codart]) agg[codart] = {codart, libelle, qte:0, nb:0};
          agg[codart].qte += qte;
          agg[codart].nb += 1;
          let d = r.DATEMV;
          if (d && !(d instanceof Date)) d = new Date(d);
          if (d instanceof Date && !isNaN(d)) {
            if (!dmin || d < dmin) dmin = d;
            if (!dmax || d > dmax) dmax = d;
          }
        });

        const nbRefs = Object.keys(agg).length;
        if (!nbRefs) { if (typeof showToast === 'function') showToast('Aucune ligne CODART/QTEMVT reconnue dans ce fichier.'); return; }

        consoImported = Object.values(agg);
        consoImportedPeriodDays = (dmin && dmax) ? Math.round((dmax - dmin) / 86400000) : CONSO_PERIOD_DAYS_DEFAULT;

        const moisImportes = (consoImportedPeriodDays / 30.4375).toFixed(1);
        if (typeof showToast === 'function') showToast(`Consommation importée : ${nbRefs} références sur ${moisImportes} mois`);

        if (typeof render === 'function') render();
        if (typeof currentView !== 'undefined' && currentView === 'conso' && typeof renderConsoPage === 'function') renderConsoPage();
      } catch (err) {
        console.error(err);
        if (typeof showToast === 'function') showToast('Erreur import consommation : ' + err.message);
      }
    };
    if (typeof loadXLSXForPdp === 'function') loadXLSXForPdp(doImport);
    else if (typeof XLSX !== 'undefined') doImport();
    else console.error('XLSX non disponible et loadXLSXForPdp introuvable');
  };
  reader.readAsArrayBuffer(file);
}

// ── Onglet dédié : tableau de toutes les références avec conso/couverture ──────
let consoSortField = 'couverture'; // couverture croissante par défaut = risques de rupture en premier
let consoSearchFilter = '';

function consoSort(field) {
  consoSortField = (consoSortField === field) ? field + '_desc' : field;
  renderConsoPage();
}

function consoSearch(val) {
  consoSearchFilter = val;
  renderConsoPage();
  const inp = document.getElementById('conso-search');
  if (inp) { inp.focus(); inp.value = val; }
}

function renderConsoPage() {
  const el = document.getElementById('view-conso');
  if (!el) return;

  const corrs = (typeof pdpGetActiveCorrespondances === 'function') ? pdpGetActiveCorrespondances() : [];
  const { items, periodDays } = consoGetActive();
  const moisPeriode = periodDays / 30.4375;

  // On part des références de correspondances (qui ont un libellé métier connu),
  // pas directement des entrées de conso brutes (qui incluent aussi matières
  // premières, consommables, etc. sans rapport avec le PDP).
  let rows = corrs.map(r => {
    const entry = consoGetEntry(r.codart_wip);
    const moyenne = consoGetMoyenneMensuelle(r.codart_wip);
    const stock = (typeof pdpGetStockForWip === 'function') ? pdpGetStockForWip(r.codart_wip) : 0;
    const couverture = consoGetCouvertureMois(r.codart_wip);
    return {
      r, entry, stock, moyenne,
      qteTotale: entry ? entry.qte : null,
      couverture,
    };
  });

  const search = consoSearchFilter.toLowerCase();
  if (search) {
    rows = rows.filter(x =>
      x.r.libelle_fg.toLowerCase().includes(search) ||
      x.r.codart_wip.toLowerCase().includes(search) ||
      x.r.client.toLowerCase().includes(search)
    );
  }

  const desc = consoSortField.endsWith('_desc');
  const field = desc ? consoSortField.slice(0,-5) : consoSortField;
  const nullsLast = (v) => v === null || v === undefined;
  rows.sort((a,b) => {
    let va, vb;
    if (field === 'couverture') { va=a.couverture; vb=b.couverture; }
    else if (field === 'stock') { va=a.stock; vb=b.stock; }
    else if (field === 'conso') { va=a.qteTotale; vb=b.qteTotale; }
    else if (field === 'produit') { va=a.r.libelle_fg.toLowerCase(); vb=b.r.libelle_fg.toLowerCase(); }
    else { va=a.couverture; vb=b.couverture; }
    if (nullsLast(va) && nullsLast(vb)) return 0;
    if (nullsLast(va)) return 1;  // pas de donnée → toujours en bas, quel que soit le sens
    if (nullsLast(vb)) return -1;
    if (typeof va === 'string') return desc ? vb.localeCompare(va) : va.localeCompare(vb);
    return desc ? vb - va : va - vb;
  });

  const nbCritique = rows.filter(x => x.couverture !== null && x.couverture < 1).length;
  const nbSurveiller = rows.filter(x => x.couverture !== null && x.couverture >= 1 && x.couverture < 3).length;
  const nbSansDonnee = rows.filter(x => x.couverture === null).length;

  const sortIcon = (f) => consoSortField === f ? '<i class="ti ti-chevron-down" style="font-size:11px"></i>'
    : consoSortField === f+'_desc' ? '<i class="ti ti-chevron-up" style="font-size:11px"></i>' : '';

  let html = '<div style="flex:1;overflow-y:auto;padding:0;display:flex;flex-direction:column">'
    + '<div style="padding:14px 20px;border-bottom:1px solid var(--border);background:var(--surface);display:flex;align-items:center;gap:12px;flex-wrap:wrap">'
    + '<h2 style="font-size:17px;font-weight:600"><i class="ti ti-trending-up" style="color:var(--accent);margin-right:8px;vertical-align:-3px"></i>Consommation &amp; couverture</h2>'
    + '<input id="conso-search" placeholder="Filtrer (référence, client)…" value="'+consoSearchFilter+'" oninput="consoSearch(this.value)" style="padding:6px 10px;border:1px solid var(--border-med);border-radius:var(--radius);background:var(--bg);color:var(--text);font-size:12px;font-family:var(--font);outline:none;width:240px">'
    + '<div style="display:flex;gap:8px;margin-left:auto;flex-wrap:wrap;align-items:center">'
    + (nbCritique ? `<span style="font-size:12px;font-weight:600;padding:4px 12px;border-radius:20px;background:#FCEBEB;color:#A32D2D"><i class="ti ti-alert-circle" style="vertical-align:-2px;margin-right:4px"></i>${nbCritique} &lt; 1 mois</span>` : '')
    + (nbSurveiller ? `<span style="font-size:12px;font-weight:600;padding:4px 12px;border-radius:20px;background:#FEF5E7;color:#633806"><i class="ti ti-clock" style="vertical-align:-2px;margin-right:4px"></i>${nbSurveiller} &lt; 3 mois</span>` : '')
    + `<span style="font-size:11px;color:var(--text-faint)">Période analysée : ${moisPeriode.toFixed(1)} mois${consoImported?' (import personnalisé)':' (par défaut)'}</span>`
    + '<label class="btn" style="font-size:11px;padding:5px 12px;cursor:pointer"><i class="ti ti-upload"></i> Importer un export<input type="file" accept=".xlsx,.xls" style="display:none" onchange="consoImportFile(this)"></label>'
    + '</div></div>';

  html += '<div style="flex:1;overflow-y:auto;padding:16px 20px">';

  if (nbSansDonnee === rows.length && rows.length) {
    html += '<div style="margin-bottom:14px;padding:12px 16px;background:var(--bg);border:1px dashed var(--border-med);border-radius:var(--radius);font-size:12px;color:var(--text-faint);text-align:center">'
      + '<i class="ti ti-info-circle" style="font-size:18px;display:block;margin-bottom:6px"></i>'
      + 'Aucune référence ne trouve de correspondance dans les données de consommation chargées.</div>';
  }

  html += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden">'
    + '<table class="cat-table" style="width:100%">'
    + '<thead><tr>'
    + '<th style="cursor:pointer" onclick="consoSort(\'produit\')">Référence '+sortIcon('produit')+'</th>'
    + '<th>Client</th>'
    + '<th style="text-align:right;cursor:pointer" onclick="consoSort(\'stock\')">Stock '+sortIcon('stock')+'</th>'
    + '<th style="text-align:right;cursor:pointer" onclick="consoSort(\'conso\')">Conso. '+moisPeriode.toFixed(0)+' mois '+sortIcon('conso')+'</th>'
    + '<th style="text-align:right">Moyenne/mois</th>'
    + '<th style="text-align:right;cursor:pointer" onclick="consoSort(\'couverture\')">Couverture '+sortIcon('couverture')+'</th>'
    + '</tr></thead><tbody>';

  rows.forEach(x => {
    const style = consoCouvertureStyle(x.couverture);
    html += `<tr style="cursor:pointer" onclick="if(typeof pdpShowDetail==='function')pdpShowDetail('${x.r.code_client}')"
      onmouseenter="this.style.background='var(--accent-light)'" onmouseleave="this.style.background=''">
      <td><div style="font-size:13px;font-weight:600">${x.r.libelle_fg}</div><div style="font-size:10px;color:var(--text-faint);font-family:monospace">${x.r.codart_wip}</div></td>
      <td style="font-size:12px">${x.r.client}</td>
      <td style="text-align:right;font-size:13px;font-weight:600">${x.stock.toLocaleString('fr')}</td>
      <td style="text-align:right;font-size:12px">${x.qteTotale!==null ? x.qteTotale.toLocaleString('fr') : '—'}</td>
      <td style="text-align:right;font-size:12px;color:var(--text-muted)">${x.moyenne!==null ? Math.round(x.moyenne).toLocaleString('fr') : '—'}</td>
      <td style="text-align:right"><span style="font-size:12px;font-weight:700;padding:3px 10px;border-radius:20px;background:${style.bg};color:${style.text}">${consoFmtMois(x.couverture)}</span></td>
    </tr>`;
  });

  html += '</tbody></table></div></div></div>';
  el.innerHTML = html;
}
